export function countryToFlag(country: string): string {
  const code = COUNTRY_TO_ISO[country.toLowerCase()]
  if (!code) return ''
  return String.fromCodePoint(
    ...[...code].map(c => 0x1F1E6 + c.charCodeAt(0) - 65)
  )
}
